#include <stdio.h>
#include <inttypes.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t L, W;
        if (scanf("%" PRId64 " %" PRId64, &L, &W) != 2) break;
        printf("%" PRId64 "\n", L * W);
    }
    return 0;
}

